package com.example.sharedreceiver;

import android.app.Activity;
import android.content.Intent;
import android.net.Uri;
import android.os.Bundle;
import android.text.TextUtils;
import android.widget.ScrollView;
import android.widget.TextView;
import android.widget.Toast;
import android.view.ViewGroup;
import android.widget.LinearLayout;
import android.widget.ImageView;
import android.graphics.Bitmap;
import android.graphics.BitmapFactory;
import java.io.InputStream;
import java.io.IOException;

public class ShareReceiverActivity extends Activity {

    private TextView textView;
    private ImageView imageView;
    private TextView uriView;
    private TextView titleView;

    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);

        ScrollView scrollView = new ScrollView(this);
        LinearLayout root = new LinearLayout(this);
        root.setOrientation(LinearLayout.VERTICAL);
        root.setPadding(32, 32, 32, 32);
        scrollView.addView(root, new ViewGroup.LayoutParams(
                ViewGroup.LayoutParams.MATCH_PARENT,
                ViewGroup.LayoutParams.WRAP_CONTENT));

        titleView = new TextView(this);
        titleView.setTextSize(20f);
        titleView.setText("Shared Content");
        root.addView(titleView);

        textView = new TextView(this);
        textView.setTextSize(16f);
        textView.setPadding(0, 24, 0, 24);
        root.addView(textView);

        imageView = new ImageView(this);
        imageView.setAdjustViewBounds(true);
        imageView.setScaleType(ImageView.ScaleType.FIT_CENTER);
        root.addView(imageView, new LinearLayout.LayoutParams(
                ViewGroup.LayoutParams.MATCH_PARENT,
                ViewGroup.LayoutParams.WRAP_CONTENT));

        uriView = new TextView(this);
        uriView.setTextSize(14f);
        uriView.setPadding(0, 24, 0, 0);
        root.addView(uriView);

        setContentView(scrollView);

        handleShareIntent(getIntent());
    }

    @Override
    protected void onNewIntent(Intent intent) {
        super.onNewIntent(intent);
        setIntent(intent);
        handleShareIntent(intent);
    }

    private void handleShareIntent(Intent intent) {
        if (intent == null) {
            showMessage("No intent received");
            return;
        }

        String action = intent.getAction();
        String type = intent.getType();

        textView.setText("");
        imageView.setImageDrawable(null);
        uriView.setText("");

        if (Intent.ACTION_SEND.equals(action)) {
            if (type != null && type.startsWith("image/")) {
                handleSharedImage(intent);
            } else if (type != null && ("text/plain".equals(type) || type.startsWith("text/"))) {
                handleSharedText(intent);
            } else {
                handleSharedGeneric(intent);
            }
        } else if (Intent.ACTION_VIEW.equals(action)) {
            handleSharedUri(intent);
        } else {
            showMessage("Unsupported share action: " + action);
        }
    }

    private void handleSharedText(Intent intent) {
        String sharedText = intent.getStringExtra(Intent.EXTRA_TEXT);
        String subject = intent.getStringExtra(Intent.EXTRA_SUBJECT);
        String title = intent.getStringExtra(Intent.EXTRA_TITLE);

        StringBuilder sb = new StringBuilder();
        if (!TextUtils.isEmpty(title)) {
            sb.append("Title: ").append(title).append("\n\n");
        }
        if (!TextUtils.isEmpty(subject)) {
            sb.append("Subject: ").append(subject).append("\n\n");
        }
        if (!TextUtils.isEmpty(sharedText)) {
            sb.append(sharedText);
        } else {
            sb.append("No text content found.");
        }

        textView.setText(sb.toString());
    }

    private void handleSharedImage(Intent intent) {
        Uri imageUri = intent.getParcelableExtra(Intent.EXTRA_STREAM);
        if (imageUri == null) {
            showMessage("No image URI found in shared intent");
            return;
        }

        try {
            InputStream inputStream = getContentResolver().openInputStream(imageUri);
            if (inputStream == null) {
                showMessage("Unable to open image stream");
                return;
            }

            Bitmap bitmap = BitmapFactory.decodeStream(inputStream);
            inputStream.close();

            if (bitmap != null) {
                imageView.setImageBitmap(bitmap);
                textView.setText("Image shared successfully");
                uriView.setText("URI: " + imageUri.toString());
            } else {
                showMessage("Unable to decode shared image");
            }
        } catch (IOException e) {
            showMessage("Error loading shared image: " + e.getMessage());
        }
    }

    private void handleSharedGeneric(Intent intent) {
        StringBuilder sb = new StringBuilder();
        sb.append("Action: ").append(intent.getAction()).append("\n");
        sb.append("Type: ").append(intent.getType()).append("\n");

        if (intent.getExtras() != null) {
            sb.append("Extras available:\n");
            for (String key : intent.getExtras().keySet()) {
                Object value = intent.getExtras().get(key);
                sb.append(key).append(": ").append(String.valueOf(value)).append("\n");
            }
        } else {
            sb.append("No extras found.");
        }

        textView.setText(sb.toString());
    }

    private void handleSharedUri(Intent intent) {
        Uri data = intent.getData();
        if (data != null) {
            uriView.setText("Opened URI: " + data.toString());
            textView.setText("Received a view intent");
        } else {
            showMessage("No URI found in ACTION_VIEW intent");
        }
    }

    private void showMessage(String message) {
        textView.setText(message);
        Toast.makeText(this, message, Toast.LENGTH_SHORT).show();
    }
}